const input = $input.first().json;
const isError = input.error || input.errorMessage || !input.data;

if (isError) {
  return [{ json: { noGames: true } }];
}

const raw = input.data || input;

let rawText = typeof raw === 'string' ? raw : JSON.stringify(raw);
let games = [];

try {
  const lines = rawText.split('\n').filter(l => l.trim());
  games = lines.map(line => JSON.parse(line));
} catch(e) {
  if (typeof raw === 'object' && !Array.isArray(raw)) {
    games = [raw];
  }
}

if (games.length === 0) {
  return [{ json: { noGames: true } }];
}

const username = 'PASTE_YOUR_LICHESS_USERNAME_HERE';
const userLower = username.toLowerCase();

const gameSummaries = games.map((game, i) => {
  const isWhite = game.players?.white?.user?.id?.toLowerCase() === userLower ||
                  game.players?.white?.user?.name?.toLowerCase() === userLower;
  const playerColor = isWhite ? 'white' : 'black';
  const opponent = isWhite ? game.players?.black : game.players?.white;
  const player = game.players?.[playerColor];

  let result = 'loss';
  if (game.winner === playerColor) result = 'win';
  else if (!game.winner) result = 'draw';

  const opening = game.opening?.name || 'Unknown';
  const speed = game.speed || 'unknown';
  const rating = player?.rating || '?';
  const oppRating = opponent?.rating || '?';
  const pgn = game.pgn || '';

  return `Game ${i+1}: ${result} as ${playerColor} (${rating} vs ${oppRating}) | ${speed} | ${opening}\nPGN: ${pgn.substring(0, 300)}`;
}).join('\n\n');

const prompt = `You are a chess coach. Analyse these ${games.length} recent games from a lichess player and identify 2-3 recurring weaknesses or patterns. Be concise, practical, and specific. Focus on actionable advice.\n\nGames:\n${gameSummaries}`;

const claudeBody = {
  model: 'claude-sonnet-4-20250514',
  max_tokens: 1024,
  messages: [{ role: 'user', content: prompt.substring(0, 15000) }]
};

return [{ json: { noGames: false, claudeBodyStr: JSON.stringify(claudeBody) } }];

const response = $input.first().json;

const content = response.content || [];
const analysisText = content
  .filter(c => c.type === 'text')
  .map(c => c.text)
  .join('\n') || 'No analysis returned';

return [{
  json: {
    discordBody: {
      embeds: [{
        title: '\u265f\ufe0f Weekly Chess Analysis',
        description: analysisText.substring(0, 2000),
        color: 10181046,
        footer: { text: 'Powered by Claude' },
        timestamp: new Date().toISOString()
      }]
    }
  }
}];

return [{
  json: {
    discordBody: {
      embeds: [{
        title: '\u265f\ufe0f Weekly Chess Analysis',
        description: 'No games found this week. Go play some chess!',
        color: 7506394,
        timestamp: new Date().toISOString()
      }]
    }
  }
}];
